import { writeOutput } from "./codegen";

// https://docs.browser-use.com/cloud/api-reference
// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:browser-use

const DOCS_URL = "https://docs.browser-use.com/cloud/api-reference";
const PLACEHOLDER_VALUE = "bu_CoffeeSafeLocalCoffeeSafeLocalCoffee";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Browser Use Cloud API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:browser-use",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const browserUseFirewall = {",
    '  name: "browser-use",',
    '  description: "Browser Use",',
    "  placeholders: {",
    `    BROWSER_USE_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.browser-use.com",',
    "      auth: {",
    "        headers: {",
    '          "X-Browser-Use-API-Key": "${{ secrets.BROWSER_USE_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Browser Use firewall config...");
  const ts = generateTypeScript();
  writeOutput("browser-use", ts, import.meta.dirname);
}
